import{_ as a,a as t,b as n}from"./chunks/配置渠道内容.HzNkdrom.js";import{_ as i,o as r,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"GitLab-Packages-Kanal hinzufügen","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/upload/gitlab-packages.md","filePath":"de-DE/upload/gitlab-packages.md","lastUpdated":1781962217000}'),l={name:"de-DE/upload/gitlab-packages.md"};function c(o,e,h,u,p,g){return r(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="gitlab-packages-kanal-hinzufugen" tabindex="-1">GitLab-Packages-Kanal hinzufügen <a class="header-anchor" href="#gitlab-packages-kanal-hinzufugen" aria-label="Permalink to &quot;GitLab-Packages-Kanal hinzufügen&quot;">​</a></h1><h2 id="was-du-vorher-brauchst" tabindex="-1">Was du vorher brauchst <a class="header-anchor" href="#was-du-vorher-brauchst" aria-label="Permalink to &quot;Was du vorher brauchst&quot;">​</a></h2><p>Du brauchst nur drei Dinge:</p><table tabindex="0"><thead><tr><th>Voraussetzung</th><th>Zweck</th></tr></thead><tbody><tr><td>GitLab-Konto</td><td>Zum Erstellen eines Access Tokens und als Besitzer des Projekts.</td></tr><tr><td>GitLab Personal Access Token</td><td>Damit ImgBed auf die GitLab API zugreifen, Projekte erstellen und Dateien in Generic Packages hochladen kann.</td></tr><tr><td>Projektname</td><td>Du kannst nur den Projektnamen eintragen, z. B. <code>imgbed</code>.</td></tr></tbody></table><h2 id="einrichtung" tabindex="-1">Einrichtung <a class="header-anchor" href="#einrichtung" aria-label="Permalink to &quot;Einrichtung&quot;">​</a></h2><h3 id="schritt-1-bei-gitlab-anmelden-und-access-token-erstellen" tabindex="-1">Schritt 1: Bei GitLab anmelden und Access Token erstellen <a class="header-anchor" href="#schritt-1-bei-gitlab-anmelden-und-access-token-erstellen" aria-label="Permalink to &quot;Schritt 1: Bei GitLab anmelden und Access Token erstellen&quot;">​</a></h3><ol><li>Melde dich bei GitLab an.</li><li>Klicke oben rechts auf deinen Avatar und öffne <code>Preferences</code>.</li><li>Öffne links <code>Access Tokens</code>.</li><li>Gib dem Token einen gut erkennbaren Namen.</li><li>Wähle eine Laufzeit, die zu deinem Wartungsrhythmus passt.</li><li>Aktiviere den Scope <code>api</code>.</li><li>Kopiere und speichere das Token direkt nach dem Erstellen.</li></ol><p><img src="'+a+'" alt="Legacy-Token erstellen" loading="lazy"></p><p><img src="'+t+'" alt="Token-Berechtigungen auswählen" loading="lazy"></p><h2 id="schritt-2-gitlab-packages-kanal-in-imgbed-ausfullen" tabindex="-1">Schritt 2: GitLab-Packages-Kanal in ImgBed ausfüllen <a class="header-anchor" href="#schritt-2-gitlab-packages-kanal-in-imgbed-ausfullen" aria-label="Permalink to &quot;Schritt 2: GitLab-Packages-Kanal in ImgBed ausfüllen&quot;">​</a></h2><p>Nachdem du in den Upload-Einstellungen <code>GitLab Packages</code> gewählt hast, fülle diese Felder aus:</p><table tabindex="0"><thead><tr><th>UI-Feld</th><th>Eingabe</th></tr></thead><tbody><tr><td>Kanalname</td><td>Ein frei gewählter Name, z. B. <code>GitLabPrimary</code>.</td></tr><tr><td>Access Token</td><td>Das gerade erstellte GitLab Personal Access Token.</td></tr><tr><td>Projektname</td><td>Entweder ein kurzer Projektname wie <code>imgbed</code> oder ein vollständiger Pfad wie <code>username/imgbed</code>.</td></tr><tr><td>Privates Repository</td><td>Je nach Bedarf ein- oder ausschalten.</td></tr><tr><td>Bemerkung</td><td>Optional, z. B. <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+n+`" alt="Kanal konfigurieren" loading="lazy"></p><h2 id="schritt-3-kanal-speichern" tabindex="-1">Schritt 3: Kanal speichern <a class="header-anchor" href="#schritt-3-kanal-speichern" aria-label="Permalink to &quot;Schritt 3: Kanal speichern&quot;">​</a></h2><p>Klicke nach dem Ausfüllen auf Speichern.</p><p>Das System übernimmt dann diese Details:</p><table tabindex="0"><thead><tr><th>Systemverhalten</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Kurzer Projektname</td><td>ImgBed erkennt das aktuelle GitLab-Konto und erweitert den Wert zu einem vollständigen Projektpfad.</td></tr><tr><td>Vollständiger Projektpfad</td><td>ImgBed verwendet <code>username/project</code> genau so, wie du es eingetragen hast.</td></tr><tr><td>Projektprüfung</td><td>Wenn du den Pfad deines aktuellen persönlichen Kontos nutzt, erstellt ImgBed das Projekt automatisch, falls es noch nicht existiert. Wenn du manuell einen vollständigen Pfad einträgst, wird dieser direkt verwendet.</td></tr><tr><td>Öffentlich/privat</td><td>Die Projektsichtbarkeit wird entsprechend dem aktuellen Schalter synchronisiert.</td></tr></tbody></table><h2 id="kurzcheck" tabindex="-1">Kurzcheck <a class="header-anchor" href="#kurzcheck" aria-label="Permalink to &quot;Kurzcheck&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bei GitLab anmelden</span></span>
<span class="line"><span>-&gt; Access Token erstellen</span></span>
<span class="line"><span>-&gt; Nur den Scope api auswählen</span></span>
<span class="line"><span>-&gt; Zu ImgBed zurückkehren und Token sowie Projektname eintragen</span></span>
<span class="line"><span>-&gt; Speichern</span></span>
<span class="line"><span>-&gt; Wenn nur ein Projektname eingetragen ist, ergänzt ImgBed automatisch den aktuellen Benutzernamen</span></span>
<span class="line"><span>-&gt; Wenn username/project eingetragen ist, nutzt ImgBed den Wert unverändert</span></span>
<span class="line"><span>-&gt; Testbild hochladen</span></span></code></pre></div>`,19)])])}const f=i(l,[["render",c]]);export{m as __pageData,f as default};
